INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('8f2727bb-47e9-53bd-bc1a-e8e4dc7a793b', '8b3242aa-721e-485b-a282-9f1917c6f65d', 'It takes ___ long time to complete the marathon.', '完成馬拉松需要一段很長的時間。', 'a', 'some', 'any', 'each', 'a 為不定冠詞，用於單數可數名詞前，表示「一個」或「一段」。', 'a 代表 one (一個)。'),
('0326857a-64d3-5684-8762-a4871554b47b', 'bbb2fcee-f431-417f-9611-641469dcd9d1', 'He is ___ a child, yet he is very responsible.', '他僅僅是一個孩子，卻非常負責。', 'but', 'very', 'quite', 'highly', 'adv. (副詞) 用於強調「僅僅」、「只」的意思。', '在文學或正式用法中，but 可當作「僅僅」來使用 → but');
